1	<script>
2		// Probe angle in degrees, 0 = pointing right, increasing counterclockwise.
3		let value = $state(90);
4		let dragging = false;
5	
6		const candidatesDef = [
7			{ id: 'c1', angle: 20 },
8			{ id: 'c2', angle: 70 },
9			{ id: 'c3', angle: 110 },
10			{ id: 'c4', angle: 160 }
11		];
12	
13		const cx = 130;
14		const cy = 130;
15	
16		function point(angleDeg, radius) {
17			const rad = (angleDeg * Math.PI) / 180;
18			return { x: cx + radius * Math.cos(rad), y: cy - radius * Math.sin(rad) };
19		}
20	
21		function clamp(v) {
22			return Math.min(360, Math.max(0, v));
23		}
24	
25		let probeTip = $derived(point(value, 100));
26	
27		// Label sits off the shaft (rotated away from the radial line, not beyond
28		// the arrowhead), so it never sits under the tip at any angle.
29		let probeLabel = $derived.by(() => {
30			const rad = (value * Math.PI) / 180;
31			const shaftR = 55;
32			const sideOffset = 20;
33			return {
34				x: cx + shaftR * Math.cos(rad) - sideOffset * Math.sin(rad),
35				y: cy - shaftR * Math.sin(rad) - sideOffset * Math.cos(rad)
36			};
37		});
38	
39		let scores = $derived(
40			candidatesDef.map((c) => {
41				const raw = Math.cos(((value - c.angle) * Math.PI) / 180);
42				const top = raw >= 0 ? 50 - raw * 50 : 50;
43				const height = Math.abs(raw) * 50;
44				return { id: c.id, angle: c.angle, score: raw, top, height };
45			})
46		);
47	
48		let bestId = $derived.by(() => {
49			let best = scores[0];
50			for (const s of scores) {
51				if (s.score > best.score) best = s;
52			}
53			return best.id;
54		});
55	
56		function angleFromPointer(e) {
57			const rect = e.currentTarget.getBoundingClientRect();
58			const centerX = rect.left + rect.width / 2;
59			const centerY = rect.top + rect.height / 2;
60			const dx = e.clientX - centerX;
61			const dy = e.clientY - centerY;
62			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
63			if (deg < 0) deg += 360;
64			value = Math.round(deg);
65		}
66	
67		function handlePointerDown(e) {
68			e.currentTarget.setPointerCapture(e.pointerId);
69			dragging = true;
70			angleFromPointer(e);
71		}
72	
73		function handlePointerMove(e) {
74			if (!dragging) return;
75			angleFromPointer(e);
76		}
77	
78		function handlePointerUp(e) {
79			dragging = false;
80			try {
81				e.currentTarget.releasePointerCapture(e.pointerId);
82			} catch (err) {
83				// pointer capture already released, ignore
84			}
85		}
86	
87		function handleKeydown(e) {
88			const step = 5;
89			let handled = true;
90			switch (e.key) {
91				case 'ArrowRight':
92				case 'ArrowUp':
93					value = clamp(value + step);
94					break;
95				case 'ArrowLeft':
96				case 'ArrowDown':
97					value = clamp(value - step);
98					break;
99				case 'Home':
100					value = 0;
101					break;
102				case 'End':
103					value = 360;
104					break;
105				default:
106					handled = false;
107			}
108			if (handled) e.preventDefault();
109		}
110	</script>
111	
112	<div class="wrapper" data-interactive="dot-alignment">
113		<p class="instruction">Turn the probe. Each bar tracks how closely it points at that candidate.</p>
114	
115		<div class="stage">
116			<div class="dial-wrap">
117				<svg class="dial" viewBox="0 0 260 260" aria-hidden="true">
118					<defs>
119						<marker id="dot-alignment-arrow-heat" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto">
120							<path d="M0,0 L8,4 L0,8 Z" style="fill: var(--data-heat)" />
121						</marker>
122						<marker id="dot-alignment-arrow-observed" markerWidth="7" markerHeight="7" refX="3.5" refY="3.5" orient="auto">
123							<path d="M0,0 L7,3.5 L0,7 Z" style="fill: var(--data-observed)" />
124						</marker>
125					</defs>
126	
127					<circle cx={cx} cy={cy} r="98" fill="none" style="stroke: var(--color-text); stroke-opacity: 0.12; stroke-width: 1.5" />
128					<circle cx={cx} cy={cy} r="3.5" style="fill: var(--color-text); fill-opacity: 0.4" />
129	
130					{#each candidatesDef as c (c.id)}
131						{@const tip = point(c.angle, 76)}
132						{@const label = point(c.angle, 98)}
133						<line
134							x1={cx}
135							y1={cy}
136							x2={tip.x}
137							y2={tip.y}
138							style="stroke: var(--data-observed); stroke-width: 2.5; stroke-opacity: 0.75"
139							marker-end="url(#dot-alignment-arrow-observed)"
140						/>
141						<text
142							x={label.x}
143							y={label.y}
144							text-anchor="middle"
145							dominant-baseline="middle"
146							style="fill: var(--color-text); font-family: var(--font-mono); font-size: 11px"
147						>{c.id}</text>
148					{/each}
149	
150					<line
151						x1={cx}
152						y1={cy}
153						x2={probeTip.x}
154						y2={probeTip.y}
155						style="stroke: var(--data-heat); stroke-width: 4"
156						marker-end="url(#dot-alignment-arrow-heat)"
157					/>
158					<text
159						x={probeLabel.x}
160						y={probeLabel.y}
161						text-anchor="middle"
162						dominant-baseline="middle"
163						style="fill: var(--color-text); font-family: var(--font-mono); font-size: 12px; font-weight: 600"
164					>probe {value}&deg;</text>
165				</svg>
166	
167				<div
168					class="slider"
169					role="slider"
170					tabindex="0"
171					aria-label="Probe angle in degrees"
172					aria-valuemin="0"
173					aria-valuemax="360"
174					aria-valuenow={value}
175					onpointerdown={handlePointerDown}
176					onpointermove={handlePointerMove}
177					onpointerup={handlePointerUp}
178					onpointercancel={handlePointerUp}
179					onkeydown={handleKeydown}
180				></div>
181			</div>
182	
183			<div class="scores">
184				{#each scores as s (s.id)}
185					<div class="score-col" class:best={s.id === bestId}>
186						<span class="score-label">{s.id}</span>
187						<div class="track">
188							<div class="zero-line"></div>
189							<div class="fill" style={`top:${s.top}%; height:${s.height}%`}></div>
190						</div>
191						<span class="score-value">{s.score.toFixed(2)}</span>
192					</div>
193				{/each}
194			</div>
195		</div>
196	</div>
197	
198	<style>
199		.wrapper {
200			display: flex;
201			flex-direction: column;
202			align-items: center;
203			gap: clamp(1rem, 3vw, 1.75rem);
204			width: 100%;
205			max-width: 640px;
206			margin: 0 auto;
207			box-sizing: border-box;
208			padding: clamp(1rem, 4vw, 2rem);
209			background: var(--color-bg);
210			color: var(--color-text);
211		}
212	
213		.instruction {
214			margin: 0;
215			text-align: center;
216			font-family: var(--font-body);
217			font-size: clamp(0.85rem, 1.6vw, 1rem);
218			opacity: 0.85;
219		}
220	
221		.stage {
222			display: flex;
223			flex-direction: column;
224			align-items: center;
225			gap: clamp(1.25rem, 4vw, 2rem);
226			width: 100%;
227		}
228	
229		.dial-wrap {
230			position: relative;
231			width: clamp(180px, 42vw, 300px);
232			aspect-ratio: 1 / 1;
233		}
234	
235		.dial {
236			width: 100%;
237			height: 100%;
238			display: block;
239		}
240	
241		.slider {
242			position: absolute;
243			inset: 0;
244			border-radius: 50%;
245			cursor: grab;
246			touch-action: none;
247		}
248	
249		.slider:focus-visible {
250			outline: 2px solid var(--color-text);
251			outline-offset: 3px;
252		}
253	
254		.scores {
255			display: flex;
256			flex-wrap: wrap;
257			justify-content: center;
258			gap: clamp(0.75rem, 3vw, 1.5rem);
259			width: 100%;
260		}
261	
262		.score-col {
263			display: flex;
264			flex-direction: column;
265			align-items: center;
266			gap: 0.4rem;
267			min-width: 4rem;
268			opacity: 0.55;
269			transition: opacity 150ms ease;
270		}
271	
272		.score-col.best {
273			opacity: 1;
274		}
275	
276		.score-label {
277			font-family: var(--font-mono);
278			font-size: 0.85rem;
279			color: var(--color-text);
280		}
281	
282		.track {
283			position: relative;
284			width: clamp(1.5rem, 4vw, 2.25rem);
285			height: 9rem;
286			background: color-mix(in srgb, var(--color-text) 6%, transparent);
287			border-radius: 0.2rem;
288		}
289	
290		.zero-line {
291			position: absolute;
292			left: 0;
293			right: 0;
294			top: 50%;
295			height: 1px;
296			background: color-mix(in srgb, var(--color-text) 35%, transparent);
297		}
298	
299		.fill {
300			position: absolute;
301			left: 0;
302			right: 0;
303			background: var(--data-params);
304			border-radius: 0.15rem;
305			transition: top 120ms ease, height 120ms ease;
306		}
307	
308		.score-col.best .fill {
309			background: var(--data-params);
310		}
311	
312		.score-value {
313			font-family: var(--font-mono);
314			font-size: 0.85rem;
315			font-weight: 600;
316			color: var(--data-params);
317		}
318	
319		@media (prefers-reduced-motion: reduce) {
320			.fill,
321			.score-col {
322				transition: none;
323			}
324		}
325	</style>
